MB 4 MT 2
Header Print Cabecalho End
Footer Print Rodape End
For Each Order EmpCod, FilCod, ViaCod Where EmpCod = &parmEmpCod //Empresa Where FilCod = &parmFilCod //Filial Where ViaCod = &parmViaCod //Viagem
//Dados Gerais RetornaFilialFaturamento.Call(EmpCod, FilCod, '', '', &FilLog, &Contato, &Contato2, &FilImg_LogRel, &FilFan) //Endereçamento // &ViaLanVlrTot = ViaLanVlrTot.ToString().Trim() //valor Total de lançamentos &ViaCTEMotVlr = ViaCteMotVlr //Valor de Comissão com a % do Motorista
&ViaPlaCar1 = ViaPlaCar1 //Placa da Carreta 1 &ViaPlaCar2 = ViaPlaCar2 //Placa da Carreta 2 &ViaPlaCar3 = ViaPlaCar3 //Placa da Carreta 3
&AuxPesCod = PesCod //Código do Motorista Do 'BuscaPessoa' //Busca Informações do Motorista
&AuxVeiCod = VeiCod //Código do Cavalo Do 'BuscaVeiculo' //Busca Informações do Cavalo
&ViaDtaSai = ViaDtaSai //Data de Saída &ViaDtaChe = ViaDtaChe.ToFormattedString() //Data de Chegada //Se não houver data de chegada imprime vazio If ViaDtaChe.IsEmpty() &ViaDtaChe = '' EndIf
&ViaVeiIniKM = Trim(ToFormattedString(ViaVeiIniKM)) //KM inicial do Cavalo //Se não Houver Km inicial, imprime vazio If &ViaVeiIniKM.IsEmpty() or ViaVeiIniKM = 0 &ViaVeiIniKM = '' EndIf
&ViaVeiFinKM = Trim(ToFormattedString(ViaVeiFinKM)) //Km final do Cavalo //Se não houver Km final, imprime vazio If &ViaVeiFinKM.IsEmpty() or ViaVeiFinKM = 0 &ViaVeiFinKM = '' EndIf
&ViaVeiTotKM = ViaVeiTotKM.ToString().Trim() //Quilometragem total da viagem //Se não houver Km Total, imprime vazio If &ViaVeiTotKM.IsEmpty() or ViaVeiTotKM = 0 &ViaVeiTotKM = '' EndIf
&AuxCidIBGE = ViaDesCidCod //Código IBGE da cidade de destino Do 'BuscaCidade' //Busca informações da cidade
//Conta quantas cargas foram entregues For Each Order EmpCod, FilCod, ViaCod, ViaCarCod Where ViaCarSts = 'E' //Status da Carga = Entregue
&AuxQtdeEntregas = Count(ViaCarCod) //Conta quantas cargas foram entregues &QtdeEntregas = Trim(ToFormattedString(&AuxQtdeEntregas)) //Atribui ao VarChar When None &QtdeEntregas = '' EndFor
Print DadosGerais
&CountAdia = 0 //Variável para contagem de impressão &AuxTotAdiantamento = 0 //Valor de Adiantamento //Adiantamentos Print TitAdiantamentos For Each Order EmpCod, FilCod, ViaCod, ViaLanCod Where ViaLanTip = 'A' //Tipo de lançamento = Adiantamento Where ViaLanSts = Status_AtivoInativo.ATIVO
//Horário de Lançamento //Se for vazio imprime 'Ñ INFORMADO' If ViaLanDta.IsEmpty() &Horario = 'Ñ INFORMADO' Else &Horario = Trim(ToFormattedString(ViaLanDta)) EndIf
&AuxPesCod = ViaLanFor //Código do Fornecedor Do 'BuscaPessoa' //Busca Fornecedor
&ViaLanObs = ViaLanObs //Observações do Lançamento &ViaLanNumDoc = ViaLanNumDoc //Número do Documento fiscal
&ViaLanVlr = Trim(ToFormattedString(ViaLanVlr)) //Valor do adiantamento
&AuxTotAdiantamento += ViaLanVlr //Soma os adiantamentos
Print ValAdiantamentos &CountAdia += 1 //Conta quantas impressões foram realizadas When None
//Se não Houver adiantamento, imprime tudo vazio &Horario.SetEmpty() &AuxPesCod.SetEmpty() &PesCodRaz.SetEmpty()
&ViaLanObs.SetEmpty() &ViaLanNumDoc.SetEmpty()
&ViaLanVlr.SetEmpty()
Print ValAdiantamentos &CountAdia = 1
EndFor
//Limpa as variáveis &Horario.SetEmpty() &AuxPesCod.SetEmpty() &PesCodRaz.SetEmpty()
&ViaLanObs.SetEmpty() &ViaLanNumDoc.SetEmpty()
&ViaLanVlr.SetEmpty()
//Abastecimentos &Count = 0 //Quantidade de impressões &ValTotAbaNum = 0 //Abastecimentos pagos &ValQtdAbaLit = 0 //Abastecimentos não pagos Print TitAbastecimentos For Each Order EmpCod, FilCod, ViaCod, ViaLanCod Where ViaLanTip = 'DA' //Tipo de lançamento = Abastecimento Where ViaLanSts = Status_AtivoInativo.ATIVO
//Horário de Lançamento If ViaLanDta.IsEmpty() &Horario = 'Ñ INFORMADO' Else &Horario = Trim(ToFormattedString(ViaLanDta)) EndIf
&AuxPesCod = ViaLanFor //Código do Fornecedor Do 'BuscaPessoa' //Busca informações do Fornecedor
&ViaLanComUfeCod = ViaLanComUfeCod //Uf de abastecimento &ViaLanVeiKm = Trim(ToFormattedString(ViaLanVeiKm)) //Quilometragem do veículo, quando abastecido &ViaLanComQtdT = Trim(ToFormattedString(ViaLanComQtdT)) //Quantidade abastecida da tração &ViaLanComQtdC = Trim(ToFormattedString(ViaLanComQtdC)) //Quantidade abastecida da Cavalo &ViaLanComQtdA = Trim(ToFormattedString(ViaLanComQtdA)) //Quantidade abastecida da Arla
&ViaLanVlr = Trim(ToFormattedString(ViaLanVlr)) //Valor do Abastecimento
//Se for pago, acrescenta aos lançamentos pagos //Se não foi pago, acrescenta aos lançamentos não pagos If ViaLanStsPag = Status_SimNao.Sim &ValTotAbaNum += ViaLanVlr //lançamentos pagos Else &AuxViaLanVlr += ViaLanVlr //lançamentos não pagos EndIf
&ValQtdAbaLit += ViaLanComQtdC //Quantidade de litros total do Cavalo abastecido
Print ValAbastecimentos
&Count += 1 //Quantidade de impressões
EndFor
//Limpa as variáveis &Horario.SetEmpty() &AuxPesCod.SetEmpty() &PesCodRaz.SetEmpty()
&ViaLanComUfeCod.SetEmpty() &ViaLanVeiKm.SetEmpty() &ViaLanComQtdT.SetEmpty() &ViaLanComQtdC.SetEmpty() &ViaLanComQtdA.SetEmpty()
&ViaLanVlr.SetEmpty()
//Calcula quanto deverá imprimir //22 é a quantidade de linhas impressas (que cabem em uma folha (configuração atual)) &CountAdia = 22 - &CountAdia //Desconta os adiantamentos e atribui &CountAdia como o total de linhas que deverá ser impresso &CountAdia = &CountAdia/2 //Divide por 2 porquê será impresso a mesma quantidade de linhas nos abastecimentos e nas despesas
//Imprime enquanto o número impresso for menor que o total calculado Do While &CountAdia > &Count Print ValAbastecimentos &Count += 1 EndDo //Despesas &Count = 0 //Quantidade de impressões Print TitDespesas For Each Order EmpCod, FilCod, ViaCod, ViaLanCod Where ViaLanTip = 'DM' OR ViaLanTip = 'DV' //Tipo de lançamento = Despesas Motorista, ou Despesa veículo Where ViaLanSts = Status_AtivoInativo.ATIVO
//Horário de Lançamento If ViaLanDta.IsEmpty() &Horario = 'Ñ INFORMADO' Else &Horario = Trim(ToFormattedString(ViaLanDta)) EndIf
&AuxPesCod = ViaLanFor //Código do Fornecedor Do 'BuscaPessoa' //Busca informações do Fornecedor
&ViaLanObs = ViaLanObs //Observações do Lançamento &ViaLanNumDoc = ViaLanNumDoc //Número do Documento fiscal
//Não usado, por enquanto ############### Do Case Case ViaLanTip = 'DM' &TipoDespesa = 'DESP. MOTORISTA' Case ViaLanTip = 'DV' &TipoDespesa = 'DESP. VEÍCULO' EndCase // ###############
&ViaLanVlr = Trim(ToFormattedString(ViaLanVlr)) //Valor da despesa
//Se não foi pago, adiciona às despesas não pagas If ViaLanStsPag = Status_SimNao.Nao &AuxDesViaLanVlr += ViaLanVlr Else &AuxViaLanVlrTot += ViaLanVlr EndIf
Print ValDespesas &Count += 1 //Quantidade de impressões
EndFor
//Limpa as variáveis &Horario.SetEmpty() &AuxPesCod.SetEmpty() &PesCodRaz.SetEmpty()
&ViaLanObs.SetEmpty() &ViaLanNumDoc.SetEmpty()
&TipoDespesa.SetEmpty() &ViaLanVlr.SetEmpty()
//Imprime enquanto o número impresso for menor que o total calculado Do While &CountAdia > &Count Print ValDespesas &Count += 1 EndDo
If Mod(&Count, 2) > 0 Print ValDespesas EndIf //Devoluções For Each Order EmpCod, FilCod, ViaCod, ViaLanCod Where ViaLanTip = 'DE' //Tipo de lançamento = Devoluções Where ViaLanSts = Status_AtivoInativo.ATIVO
&ValDespesas += ViaLanVlr //Valor de devoluções
EndFor
Exit EndFor
//Adiantamento &TotAdiantamento = Trim(ToFormattedString(&AuxTotAdiantamento))
//Abastecimentos &TotAbastecimento = Trim(ToFormattedString(&ValTotAbaNum))
//Despesas Pagas &ViaLanVlrTot = Trim(ToFormattedString(&AuxViaLanVlrTot))
//Saldo &AuxTotSaldo = (&AuxTotAdiantamento - &AuxViaLanVlrTot) - &ValTotAbaNum &TotSaldo = Trim(ToFormattedString(&AuxTotSaldo))
//Despesas Não pagas &NPagoDespesas = Trim(ToFormattedString(&AuxDesViaLanVlr))
//Abastecimentos não pagos &NPagoViaLanVlr = Trim(ToFormattedString(&AuxViaLanVlr))
//Custo L/KM If &ViaVeiTotKM.ToNumeric() > 0 &AuxValTotAbaNum = &ValTotAbaNum + &AuxViaLanVlr &MedLKMNum = &AuxValTotAbaNum/&ViaVeiTotKM.ToNumeric() &MedLKM = Trim(ToFormattedString(&MedLKMNum)) Else &MedLKM = 'N/A' EndIF
//Quantidade abastecido If &ValQtdAbaLit > 0 &TotLitros = Trim(ToFormattedString(&ValQtdAbaLit)) Else &TotLitros = 'N/A' EndIf
//Media KM por L If &ValQtdAbaLit > 0 &MedKMLNum = &ViaVeiTotKM.ToNumeric()/&ValQtdAbaLit &MedKML = Trim(ToFormattedString(&MedKMLNum)) Else &MedKML = 'N/A' EndIf
//Devolução &TotDevolucao = Trim(ToFormattedString(&ValDespesas))
//Vale &ValVale = &AuxTotSaldo - &ValDespesas &TotVale = Trim(ToFormattedString(&ValVale))
//Comissão &TotComissao = Trim(ToFormattedString(&ViaCTEMotVlr)) &AuxTotComissaoFinal= &ViaCTEMotVlr - &ValVale &TotComissaoFinal = Trim(ToFormattedString(&AuxTotComissaoFinal))
Print TitValores Print ValTotal Print ValTot2 Print ValTot3 Print ValTot4 Print ValTot5 Print ValTot6
Sub 'BuscaPessoa'
For Each Order EmpCod, PesCod Where EmpCod = &parmEmpCod Where PesCod = &AuxPesCod
If PesCodRaz.Trim().Length() > 39 &PesCodRaz = SubStr(Trim(PesCodRaz), 1, 36) &PesCodRaz = &PesCodRaz.Trim() + '...' Else &PesCodRaz = PesCodRaz EndIf
Exit EndFor
EndSub
Sub 'BuscaVeiculo'
For Each Order EmpCod, VeiCod Where EmpCod = &parmEmpCod Where VeiCod = &AuxVeiCod
&VeiPla = VeiPla
Exit EndFor
EndSub
Sub 'BuscaCidade'
For Each Order EmpCod, CidCod Where EmpCod = &parmEmpCod Where CidIBGE = &AuxCidIBGE
&CidadeDestino = Trim(UfeCod) + ' - ' + Trim(CidNom)
Exit EndFor
EndSub
